MultiLanguageSpellData['pt'][465999] = {name = "Rosnadora Couraçada Carmesim", additional_info = "1.5 seg de lançamento\n[q]Evoca e dispensa esta montaria.\n[q]\"Alguns goblins se referem carinhosamente a hienas treinadas como \"rosnadoras\". Esta gosta muito de cavar.\"\nComerciante:\nRolo Razabum\nÁrea:\nInframina\nCusto:\n8125"}
MultiLanguageSpellData['pt'][466000] = {name = "Nhocpactador de Sombrafuso", additional_info = "1.5 seg de lançamento\n[q]Evoca e dispensa esta montaria.\n[q]\"Considerado o Maioral entre as hienas do Ferro-velho do Stix, sua mordida tem força suficiente para esmigalhar qualquer coisa, ou pessoa, em que Gallywix queira dar sumiço.\"\nComerciante:\nAndo, o Gato\nÁrea:\nLibertação da Inframina\nCusto:\n500"}
MultiLanguageSpellData['pt'][466001] = {name = "Esmaga-ossos de Aguanegra", additional_info = "1.5 seg de lançamento\n[q]Evoca e dispensa esta montaria.\n[q]\"É melhor guardar esses ossos se não quiser que eles acabem esmagados.\"\nSaque:\nArca Aguanegra\nÁrea:\nInframina"}
MultiLanguageSpellData['pt'][466002] = {name = "Rosnadora Couraçada Violeta", additional_info = "1.5 seg de lançamento\n[q]Evoca e dispensa esta montaria.\n[q]\"Toco sabe uma coisa ou outra sobre cuidar de hienas. Regra número um: mantenha as mãos longe dos dentes!\"\nComerciante:\nToco Fineza\nÁrea:\nInframina\nCusto:\n8125"}
