MultiLanguageSpellData['pt'][466011] = {name = "Flarendo, o Furioso", additional_info = "1.5 seg de lançamento\n[q]Evoca e dispensa esta montaria.\n[q]\"Ser VIP dos VIPs no Gallagio tem suas vantagens. Elas incluem a chave desse ex-Rei da Carnificina. A mais alta tecnologia goblínica de ponta permite que ele faça mais de 20 metros por litro!\""}
MultiLanguageSpellData['pt'][466012] = {name = "Falha do Tambor Trovejante", additional_info = "1.5 seg de lançamento\n[q]Evoca e dispensa esta montaria.\n[q]\"Obtida na geral do Caldeirão durante um confronto especialmente encarniçado. Quando foi perguntado se tinha falhado, o operador de Torq respondeu apenas: \"Parece que sim, né?\".\"\nComerciante:\nAndo, o Gato\nÁrea:\nLibertação da Inframina\nCusto:\n500"}
