MultiLanguageSpellData['pt'][466020] = {name = "Goblin da S.U.C.A.T.A. Personalizado", additional_info = "1.5 seg de lançamento\n[q]Evoca e dispensa esta montaria.\n[q]\"Retalhadores goblínicos já provaram várias vezes que têm muitas aplicações, como extração de madeira e transporte. Este modelo foi reprogramado para ser usado pela S.U.C.A.T.A.\"\nSaque:\nPilha de Sucata Peneirada\nÁrea:\nInframina"}
