MultiLanguageSpellData['pt'][467024] = {name = "Carregador de Jaka'Cola", additional_info = "[q]Agora, Curiosidades Desviadas têm 35% de chance de conter 1 Jaka'Cola e, uma vez por imersão, Brann evoca um Jaka'Pack com 6 Jaka'Colas quando cria fogueiras.\n\n São diversos sabores de Jaka'Cola, e cada um aplica um efeito quando coletado."}
MultiLanguageSpellData['pt'][467026] = {name = "Granada Goblomagnética Quicante", additional_info = "[q]Brann tem chance durante o combate de arremessar uma granada GGQ em um inimigo selecionado, causando dano de Natureza moderado com 20% de chance de atordoar por 1.5 s. Tem 25% de chance de quicar para outro alvo.\n\n A granada pode quicar entre integrantes do grupo sem perigo."}
MultiLanguageSpellData['pt'][467029] = {name = "Matriz de Conversão de Impacto", additional_info = "[q]Ao entrar em combate, Brann ativa a matriz de conversão por 10 s. Um pequeno percentual de todo o dano causado pelo grupo durante esse período é convertido em atributo primário e distribuído aos integrantes do grupo.\n\n Quando a matriz de conversão perde força, o bônus de atributo primário persiste por 10 s. Este efeito só pode ocorrer uma vez a cada 2 min."}
MultiLanguageSpellData['pt'][467031] = {name = "Torrente de Sangue Negro", additional_info = "Alcance ilimitado\nInstantâneo\n[q]Sangue Negro verte do teto da fábrica, causando 14 de dano de Sombra a cada 0.5 s."}
MultiLanguageSpellData['pt'][467032] = {name = "Fogo Ovado", additional_info = nil}
MultiLanguageSpellData['pt'][467033] = {name = "Radar S4qu3", additional_info = "[q]A cada 60 s ou 5 s após entrar em combate, escaneia o ambiente, destacando Curiosidades Desviadas e fazendo inimigos com menos de 95% dos pontos de vida receber 4% a mais de dano por 10 s."}
MultiLanguageSpellData['pt'][467034] = {name = "Bomba Goblínica Mortífera Feita com Engenharia Reversa", additional_info = "[q]Quando os pontos de vida de algum jogador caírem para menos de 50% durante o combate, Brann arremessa uma bomba gigante que explode com o impacto.\n\n A explosão repele e desacelera em 45% os inimigos por 5 s, além de curar 35% do máximo de pontos de vida dos integrantes do grupo próximos. Só pode ocorrer a cada 1.5 min."}
MultiLanguageSpellData['pt'][467035] = {name = "Ímã Comicamente Grande", additional_info = "[q]Se Brann usar Ferramentas de Coleta , ele tem 100% de chance de magnetizar Blindagens Descartadas para integrantes do grupo, concedendo 5% do máximo de pontos de vida deles como um escudo que se regenera fora de combate.\n\n Ferramentas de Coleta\nBrann usa suas ferramentas de coleta para ajudar os jogadores a encontrar ouro, minério, plantas, peixe, couro e tesouros adicionais."}
MultiLanguageSpellData['pt'][467036] = {name = "Mecanismo de Foguete a Biocombustível", additional_info = "[q]Os integrantes do grupo são equipados com um Mecanismo de Foguete a Biocombustível .\n\n Biocombustível\n Cada inimigo abatido alimenta o Mecanismo de Foguete a Biocombustível , aumentando em 2% a velocidade de movimento e em 2% a aceleração por 10 s. Acumula até 10 vezes."}
MultiLanguageSpellData['pt'][467037] = {name = "Chip de Aprimoramento Triangulado", additional_info = "[q]O máximo de pontos de vida de Brann aumenta em 4%, e o dano causado e a cura realizada dele aumentam em 20%.\n\n Em combate, Brann pode ser alvo de robôs mecânicos que se fixam nele e podem ser destruídos ou dissipados. Se o alcançarem, Brann recebe 30% do máximo de pontos de vida dele em dano e fica atordoado por 5 s."}
