MultiLanguageSpellData['pt'][468033] = {name = "Runa Tempestuosa do Lança-runa", additional_info = "[q]Cada 6 s em combate leva a runa à sobrecarga, atingindo um inimigo próximo com um raio que causa 187 de dano de Natureza.\n\n Este efeito é ativado imediatamente, na primeira vez que você atinge uma criatura."}
MultiLanguageSpellData['pt'][468034] = {name = "Orbe do Singramares Ondanegra", additional_info = "Aproximadamente 4 procs por minuto\n[q]Seus feitiços e habilidades de longo alcance têm chance de atirar um glóbulo de água em um inimigo, causando 259 de dano de Gelo a ele e a mais 4 inimigos em um raio de 7 m dele."}
