MultiLanguageSpellData['pt'][470596] = {name = "Estouro de Fogofrio", additional_info = "Alcance de 100m\nInstantâneo\n[q]Gélido\nLançar Chuva de Cometas faz seu próximo uso de Lança de Gelo explodir em um Estouro de Fogofrio, causando ([265.6% of Spell Power]) de dano de Fogofrio aos inimigos próximos. Dano reduzido acima de 8 alvos.\n\n Estouro de Fogofrio tem 50% de chance de conceder Congelamento Cerebral.\n\nFogo\nLançar Meteoro faz seu próximo uso de Impacto de Fogo explodir em um Estouro de Fogofrio, causando ([265.6% of Spell Power]) de dano de Fogofrio aos inimigos próximos. Dano reduzido acima de 8 alvos.\n\n Estouro de Fogofrio reduz em 5 s a recarga de Chamas da Fênix."}
