MultiLanguageSpellData['pt'][471876] = {name = "Uivo do Líder da Alcateia", additional_info = "[q]Domínio das Feras\n Em combate, a cada 30 s seu próximo Comando para Matar evoca a ajuda de uma Fera.\n\n Mantícora\n Uma Mantícora desce dos céus, soltando um brado de batalha que aumenta em 10% o dano causado por você e pelos seus ajudantes por 15 s.\n\n Javali\n Um Javali investe contra seu alvo 3 vezes, causando ([400% of Attack Power]) de dano Físico ao alvo primário e ([160% of Attack Power]) de dano a até 8 inimigos próximos.\n\n Urso\n Um Urso entra na briga, rasgando a carne dos inimigos, causando ([400% of Attack Power]) de dano ao longo de 10 s a até 8 inimigos próximos.\n\nSobrevivência\n Em combate, a cada 30 s seu próximo Comando para Matar evoca a ajuda de uma Fera.\n\n Mantícora\n Uma Mantícora desce dos céus, soltando um brado de batalha que aumenta em 15% o dano causado por você e pelos seus ajudantes por 15 s.\n\n Javali\n Um Javali investe contra seu alvo 3 vezes, causando ([400% of Attack Power]) de dano Físico ao alvo primário e ([160% of Attack Power]) de dano a até 8 inimigos próximos.\n\n Urso\n Um Urso entra na briga, rasgando a carne dos inimigos, causando ([400% of Attack Power]) de dano ao longo de 10 s a até 8 inimigos próximos."}
