MultiLanguageSpellData['pt'][1216895] = {name = "Controle do Sonho - Reiniciar Rastreador", additional_info = "Instantâneo\n[q]Equilíbrio\nO tempo decorrido enquanto suas principais habilidades estão disponíveis para uso ou com o máximo de carga é subtraído do tempo de recarga dessas habilidades após a próxima vez que você as usar, até no máximo 15 s.\n\n Afeta Força da Natureza, e Convocar Espíritos.\n\nRestauração\nO tempo decorrido enquanto suas principais habilidades estão disponíveis para uso ou com o máximo de carga é subtraído do tempo de recarga dessas habilidades após a próxima vez que você as usar, até no máximo 15 s.\n\n Afeta Rapidez da Natureza, Encarnação: Árvore da Vida, e Convocar Espíritos."}
