MultiLanguageSpellData['pt'][1225061] = {name = "Adicionando", additional_info = "1.5 seg de lançamento\nReagentes:\nAreias de K'aresh\n[q]Quando Brann usa Ferramentas de Coleta , areia começa a rodopiar em torno de integrantes do grupo, concedendo 6 % de acerto crítico até 10 vezes e desacelerando em 6 % os inimigos próximos.\n\n Obter um acerto crítico cria no local do alvo, por 6 s, um Diabo da Areia que puxa inimigos periodicamente para o meio. Só pode ocorrer a cada 45 s.\n\n Ferramentas de Coleta\nBrann usa suas ferramentas de coleta para ajudar os jogadores a encontrar ouro, minério, plantas, peixe, couro e tesouros adicionais.\n\nVocê já tem este badulaque na sua coleção."}
