MultiLanguageSpellData['pt'][1229189] = {name = "Óculos Tintos de Mana", additional_info = "[q]Brann coloca óculos tintos de mana em combate, aumentando periodicamente em 4% o dano que ele causa e em 5% o dano recebido a cada 5 s, até 10 vezes.\n\n Dissipar os óculos cura 25% do máximo de pontos de vida de Brann e atordoa inimigos próximos por 2 s.\n Caso contrário, este efeito se dissipa automaticamente quando Brann chega a menos de 30% dos pontos de vida, impedindo o atordoamento."}
