MultiLanguageSpellData['pt'][1235959] = {name = "Mage Spellslinger 11.2 Class Set 2pc", additional_info = "[q]Arcano\n Dano de Impacto Arcano aumentado em 12%, e Impacto Arcano concede 1 aplicação de Harmonia Arcana. Dano direto de Farpa tem 25% de chance de conceder uma aplicação de Harmonia Arcana.\n\nFogo, Gélido\n Dano de Lança de Gelo e Sincelo aumentado em 10%, e Lança de Gelo tem 50% de chance de gerar 1 aplicação de Frente Fria. Dano direto de Farpa tem 15% de chance de conceder uma aplicação de Frente Fria."}
MultiLanguageSpellData['pt'][1235962] = {name = "Mage Sunfury 11.2 Class Set 2pc", additional_info = "[q]Arcano, Fogo, Gélido\n Bônus de dano mágico de Esfera de Fogo Místico aumentado em 1.0%. Cascata de Mana agora concede mais 0.5% de Aceleração por aplicação."}
MultiLanguageSpellData['pt'][1235963] = {name = "Mage Frostfire 11.2 Class Set 2pc", additional_info = "[q][ Fogo : Dano de Chuva de Cometas e Estouro de Fogofrio aumentado em 15%. Dano de Seta de Fogofrio aumentado em 8%. Chuva de Cometas, Estouro de Fogofrio e Seta de Fogofrio agora aplicam Incendiar com 75% da eficácia /\n\nArcano, Gélido\nDano de Meteoro e Estouro de Fogofrio aumentado em 30%. Dano de Seta de Fogofrio aumentado em 10%. Meteoro, Estouro de Fogofrio e Seta de Fogofrio agora aplicam Incendiar, causando 25% de dano adicional ao longo de 9 s ]"}
MultiLanguageSpellData['pt'][1235964] = {name = "Mage Spellslinger 11.2 Class Set 4pc", additional_info = "[q]Arcano\n Dano de Farpa aumentado em 8%. Orbe Arcano tem 100% de chance de conceder uma aplicação de Harmonia Arcana, até um máximo de 8 vezes. Ao chegar a 20 aplicações de Harmonia Arcana, recebe Intuição com 100% da eficácia.\n\nFogo\n Dano de Farpa aumentado em 8%. Orbe Arcano tem 100% de chance de conceder uma aplicação de Harmonia Arcana, até um máximo de 8 vezes. Quando Frente Fria evoca um Orbe Congelado, seu dano mágico aumenta em 8% por 10 s.\n\nGélido\n Quando causa dano a um ou mais inimigos, Orbe Congelado tem 15% de chance de conceder uma aplicação de Frente Fria. Quando Frente Fria evoca um Orbe Congelado, seu dano mágico aumenta em 8% por 10 s.\n(100ms de recarga)"}
MultiLanguageSpellData['pt'][1235965] = {name = "Mage Sunfury 11.2 Class Set 4pc", additional_info = "[q]Fogo, Gélido\n Feitiços excepcionais lançados pela sua Fênix adicionam 0.3 s à duração da sua próxima Hipertermia. Ao expirar, sua Fênix potencializa você mais ainda, concedendo Distorção Temporal Menor e 10% a mais de dano mágico por 10 s.\n\nArcano\n Feitiços excepcionais lançados pela sua Fênix adicionam 0.5 s à duração da sua próxima Alma Arcana. Ao expirar, sua Fênix potencializa você mais ainda, concedendo Distorção Temporal Menor e 20% a mais de dano mágico por 10 s."}
MultiLanguageSpellData['pt'][1235966] = {name = "Mage Frostfire 11.2 Class Set 4pc", additional_info = "[q]Fogo\n O lançamento de Ignimpacto tem 20% de chance de lançar também Punhal Glacial, causando ([366.24% of Spell Power]) de dano de Gelo. Punhais Glaciais lançados assim não enraízam. Além disso, Punhal Glacial agora se beneficia de Incendiar.\n\nArcano, Gélido\n O lançamento de Punhal Glacial tem 100% de chance de lançar também Ignimpacto, causando ([352.5% of Spell Power]) de dano de Fogo. Além disso, Ignimpacto agora se beneficia de Incendiar."}
