MultiLanguageSpellData['pt'][1236332] = {name = "Druid Elune's Chosen 11.2 Class Set 2pc", additional_info = "[q]Equilíbrio\n Dano de Fogo Estelar aumentado em 25%. Ao ganhar Poder Astral com Fogo Estelar, você tem 50% de chance de lançar um Surto Estelar contra uma vítima com 50% de eficácia.\n\nFeral, Guardião, Restauração\n Dano de Surra aumentado em 20%. Surra tem 40% de chance de lançar um Surto Estelar contra uma vítima com 160% de eficácia.\n(100ms de recarga)"}
MultiLanguageSpellData['pt'][1236333] = {name = "Druid Elune's Chosen 11.2 Class Set 4pc", additional_info = "[q]Equilíbrio\n No impacto, Surtos Estelares lançados por Fogo Estelar se dividem em até 3 alvos adicionais com 80% de eficácia e concedem uma aplicação de Luar Crescente. O lançamento de Fúria de Eluna ou Lua Cheia consome Luar Crescente para aumentar em 4% seu dano por aplicação por 12 s.\n\nFeral, Guardião, Restauração\n No impacto, Surtos Estelares lançados por Surra se dividem em até 3 alvos adicionais com 20% de eficácia e concedem uma aplicação de Luar Crescente. O lançamento de Feixe Lunar consome Luar Crescente para aumentar em 4% seu dano por aplicação por 12 s."}
MultiLanguageSpellData['pt'][1236334] = {name = "Druid Keeper of the Grove 11.2 Class Set 2pc", additional_info = "[q]Equilíbrio, Feral, Guardião\n O lançamento de Alinhamento Celestial invoca a ajuda de uma dríade por 10 s, que lança Surto Estelar com 360% de eficácia e Chuva Estelar com 800% de eficácia.\n\nRestauração\n O lançamento de Encarnação: Árvore da Vida ou Convocar Espíritos invoca a ajuda de uma dríade por 5 s, que lança Tranquilidade com 50% de eficácia e Recrescimento instantâneo com 200% de eficácia em seu aliado com menos pontos de vida."}
MultiLanguageSpellData['pt'][1236336] = {name = "Druid Keeper of the Grove 11.2 Class Set 4pc", additional_info = "[q]Restauração\n Quando sua Dríade se esvai, seus próximos 2 lançamentos de Recomposição Rápida realizam cura adicional equivalente a 5% da sua cura enquanto ela estava ativa e atingem aliados próximos com 25% de sua cura, reduzido acima de 5 alvos.\n\nEquilíbrio, Feral, Guardião\n Quando sua Dríade se esvai, seus próximos 2 lançamentos de Surto Estelar causam dano adicional equivalente a 2% do seu dano enquanto ela estava ativa e atingem inimigos próximos com 10% de seu dano, reduzido acima de 5 alvos."}
MultiLanguageSpellData['pt'][1236337] = {name = "Druid Wildstalker 11.2 Class Set 2pc", additional_info = "[q]Equilíbrio, Guardião, Restauração\n A taxa de crescimento de Floresceres Simbióticos aumenta em 30%. O lançamento de Recrescimento com Abstração faz Floresceres Simbióticos crescerem em até 2 aliados próximos válidos.\n\nFeral\n A taxa de crescimento de Vinhas Sanguinárias aumenta em 40%. Fúria do Tigre faz Vinhas Sanguinárias crescerem em até 3 inimigos próximos válidos."}
MultiLanguageSpellData['pt'][1236338] = {name = "Druid Wildstalker 11.2 Class Set 4pc", additional_info = "[q]Equilíbrio, Guardião, Restauração\n Floresceres Simbióticos têm 20% de chance de ativar Crescimento Explosivo a cada 2 s com 80% de eficácia. Cada aplicação de Floresceres Simbióticos em um aliado aumenta em 30% a cura de Crescimento Explosivo.\n\nFeral\n Vinhas Sanguinárias têm 20% de chance de ativar Crescimento Explosivo a cada 2 s com 100% de eficácia. Cada aplicação de Vinhas Sanguinárias em um inimigo aumenta em 40% o dano de Crescimento Explosivo."}
