MultiLanguageSpellData['pt'][1236356] = {name = "Death Knight Rider of the Apocalypse 11.2 Class Set 4pc", additional_info = "[q][ Gélido : O lançamento de Obliterar ou Foice Gélida manda Matatroll lançar também Obliterar ou Foice Gélida junto de você, com 100% de eficácia. Seu Obliterar causa 20% a mais de dano a alvos afetados pela Fúria Gélida de Matatroll /\n\nSangue, Profano\nO lançamento de Espiral da Morte ou Epidemia manda Cristalba lançar também Espiral da Morte ou Epidemia junto de você com 125% de eficácia. Sua Espiral da Morte causa 40% a mais de dano a alvos afetados pela Morte-viva de Cristalba ](500ms de recarga)"}
