MultiLanguageSpellData['pt'][1236360] = {name = "Demon Hunter Aldrachi Reaver 11.2 Class Set 4pc", additional_info = "[q]Vingança\n Fúria dos Aldrachi potencializa mais Cutilada da Alma ao ser lançada após Talhar, aumentando em 12 os cortes.\n\n Marca do Aniquilador agora acumula até 2 vezes e potencializa mais Talhar ao ser lançada após Cutilada da Alma, concedendo uma aplicação adicional por 100% da duração normal.\n\nDevastação\n Fúria dos Aldrachi potencializa mais Dança de Lâminas ao ser lançada após Golpe do Caos, aumentando em 12 os cortes.\n\n Marca do Aniquilador agora acumula até 2 vezes e potencializa mais Golpe do Caos ao ser lançada após Dança de Lâminas, concedendo uma aplicação adicional por 100% da duração normal."}
