MultiLanguageSpellData['pt'][1236362] = {name = "Demon Hunter Fel-Scarred 11.2 Class Set 4pc", additional_info = "[q]Devastação\n Entrar na forma demoníaca agora induz imediatamente um Surto Demoníaco e estilhaça um fragmento de alma de demônio que concede 20% a mais de dano por 10 s.\n\nVingança\n Entrar na forma demoníaca agora induz imediatamente um Surto Demoníaco e estilhaça um fragmento de alma de demônio que concede 20% a mais de dano por 15 s.\n(100ms de recarga)"}
MultiLanguageSpellData['pt'][1236364] = {name = "Evoker Flameshaper 11.2 Class Set 2pc", additional_info = "[q]Engolfar atiça sua Chama Interior, aumentado em 25% seu dano e sua cura ao longo do tempo e aumentando em 50% por 12 s sua chance de ganhar Estouro de Essência. Acumula até 2 vezes. Várias aplicações podem se sobrepor."}
MultiLanguageSpellData['pt'][1236365] = {name = "Evoker Flameshaper 11.2 Class Set 4pc", additional_info = "[q]O consumo de Estouro de Essência durante Chama Interior dispara uma Bomba de Essência contra seu alvo, [ Devastação : causando ([371% of Spell Power]) de dano Arcano a inimigos próximos /\n\nPreservação, Aprimoramento\ncurando aliados próximos por ([250% of Spell Power]) ] Efeito reduzido acima de 5 alvos."}
MultiLanguageSpellData['pt'][1236366] = {name = "Evoker Scalecommander 11.2 Class Set 2pc", additional_info = "[q]Aprimoramento ( Conjurante de Aprimoramento )\n Enquanto estiver voando durante Respiração Profunda e até 20 s depois, você comanda um esquadrão de 2 dracthyr, que atacarão seus alvos com Desintegrar e Pira.\n\n Devastação, Preservação\n Enquanto estiver voando durante [ Sopro Eônico / Respiração Profunda] e até 10 s depois, você comanda um esquadrão de 2 dracthyr, que atacarão seus alvos com Desintegrar e Pira."}
MultiLanguageSpellData['pt'][1236367] = {name = "Evoker Scalecommander 11.2 Class Set 4pc", additional_info = "[q]Aprimoramento ( Conjurante de Aprimoramento )\n Quando seu esquadrão estiver ativo, sua Erupção em Massa atinge até 2 alvo adicional. Além disso, seu esquadrão ajuda você por mais 10 s.\n\n Devastação, Preservação\n Quando seu esquadrão estiver ativo, sua [ Devastação : Desintegração em Massa /\n\nPreservação, Aprimoramento\nErupção em Massa ] atinge até 2 alvo adicional. Além disso, seu esquadrão ajuda você por mais 5 s."}
