MultiLanguageSpellData['pt'][1236807] = {name = "Benesse da Dríade", additional_info = "Instantâneo\n[q]Restauração\nQuando sua Dríade se esvai, seus próximos 2 lançamentos de Recomposição Rápida realizam cura adicional equivalente a 5% da sua cura enquanto ela estava ativa e atingem aliados próximos com 25% de sua cura, reduzido acima de 5 alvos.\n\nEquilíbrio, Feral, Guardião\nQuando sua Dríade se esvai, seus próximos 2 lançamentos de Surto Estelar causam dano adicional equivalente a 2% do seu dano enquanto ela estava ativa e atingem inimigos próximos com 10% de seu dano, reduzido acima de 5 alvos."}
