MultiLanguageSpellData['pt'][1236991] = {name = "Caos Devorador", additional_info = "Alcance de 100m\nInstantâneo\n[q]Receber dano tem chance elevada de fazer você devorar a essência de inimigos próximos, causando 1923 de dano de Sombra dividido entre eles. Além disso, você recupera pontos de vida equivalentes a 150% do dano causado.\n\n Ao receber dano fatal de até 18656 , você fica com 20% dos seus pontos de vida e se reconstitui como caos instável por 6 s. Exceda 65% dos seus pontos de vida para se estabilizar e evitar a morte. Esse efeito pode ocorrer uma vez a cada 8 min. O Núcleo não pode causar dano enquanto recarrega."}
