MultiLanguageSpellData['pt'][1245357] = {name = "Grifo de Northeron Adornado", additional_info = "1.5 seg de lançamento\n[q]Evoca e dispensa esta montaria.\n[q]\"Os cavalga-grifos e sumos xamãs anciãos dos Martelo Feroz de Northeron com frequência adornavam seus grifos com peças intrincadas, recobertas de penas, usadas para indicar sua patente e seu prestígio.\"\nPosto Comercial"}
MultiLanguageSpellData['pt'][1245358] = {name = "Grifo do Ninho da Águia do Sumo Xamã", additional_info = "1.5 seg de lançamento\n[q]Evoca e dispensa esta montaria.\n[q]\"Os primeiros xamãs Martelo Feroz que se depararam com grifos acreditavam que eles fossem espíritos elementais em forma mortal. Este encontro marcaria o clã Martelo Feroz por gerações.\"\nPosto Comercial"}
MultiLanguageSpellData['pt'][1245359] = {name = "Grifo do Planalto Candente", additional_info = "1.5 seg de lançamento\n[q]Evoca e dispensa esta montaria.\n[q]\"A lenda dos Martelo Feroz diz que a plumagem alaranjada dos grifos é um traço hereditário, passado de ancestrais elementais.\"\nPosto Comercial"}
