MultiLanguageSpellData['pt'][1245361] = {name = "Guia Celeste Brasalado", additional_info = "1.5 seg de lançamento\n[q]Evoca e dispensa esta montaria.\n[q]\"Dos contrafortes de Khaz Modan, seguimos suas asas em brasa viva: uma tocha voltada para o norte nos céus escuros do verão.\" - A Peregrinação do Primeiro Sábio Feroz\nPosto Comercial"}
