MultiLanguageSpellData['pt'][1249462] = {name = "Acordo: Cartel Zo", additional_info = "Instantâneo\n[q]Faz com o Cartel Zo um acordo que confere o direito de se proclamar um deles (por uma semana).\n\n Contrato de Bando de Guerra\n Só é possível fazer o acordo com um Cartel por semana. Este efeito é compartilhado com todo o seu Bando de Guerra."}
MultiLanguageSpellData['pt'][1249463] = {name = "[q3]Acordo: Cartel Zo", additional_info = "3.5 seg de lançamento\nReagentes:\nPergaminho Novo , Instrumento Manaforjado , Tinta Banhada de Sol (25)\nVândalos da Manaforja\nRenome:\n8\nLocal:\nPonto Sombrio\n\n[q3]Acordo: Cartel Zo\n[q2]Uso: Faz com o Cartel Zo um acordo que confere o direito de se proclamar um deles (por uma semana).\n\n Contrato de Bando de Guerra\n Só é possível fazer o acordo com um Cartel por semana. Este efeito é compartilhado com todo o seu Bando de Guerra.\n70\n[q]\"Um \"contrato\" de curto prazo elaborado por escribas, prometendo a lealdade de um Bando de Guerra a um cartel de Corretores.\""}
MultiLanguageSpellData['pt'][1249464] = {name = "Dom de Eluna", additional_info = "Instantâneo\n[q]Domínio das Feras, Sobrevivência\nDano de Bomba de Fogo Indômito aumentado em 10%. Quando Tempestade Lunar se esvai, você ganha Dom de Eluna, fazendo com que, ao lançar Bomba de Fogo Indômito mais 2 vezes, você cause dano Arcano, com o dano inicial aumentado em 150%.\n\nPrecisão\nDano de Tiro Rápido aumentado em 25%. Quando Tempestade Lunar se esvai, você ganha Dom de Eluna, fazendo com que, ao lançar Tiro Certo mais 2 vezes, você cause dano Arcano, com o dano aumentado em 10%."}
