MultiLanguageSpellData['pt'][1250314] = {name = "Flor-fantasma", additional_info = "Alcance de 5m\n2.5 seg de lançamento\n[q]A Flor-fantasma é um resquício energético da flora nativa de K'aresh, impossível de incorporar a receitas algari.\n\n Em vez de fazer isso, você pode trocar a Flor-fantasma no Mercado de Recursos por materiais algari. Como os preços mudam a cada dia, ter paciência pode ajudar você a conseguir as melhores barganhas!"}
MultiLanguageSpellData['pt'][1250317] = {name = "Flor-fantasma Exuberante", additional_info = "Alcance de 5m\n2.5 seg de lançamento\n[q]A Flor-fantasma é um resquício energético da flora nativa de K'aresh, impossível de incorporar a receitas algari.\n\n Em vez de fazer isso, você pode trocar a Flor-fantasma no Mercado de Recursos por materiais algari. Como os preços mudam a cada dia, ter paciência pode ajudar você a conseguir as melhores barganhas!\n\n Foram encontradas algumas amostras de Flor-fantasma notavelmente maiores que o esperado. Esta era uma das poucas plantas capazes de sobreviver ao deserto inclemente de K'aresh, e sabe-se que algumas variedades maiores cresciam em meio à exuberância das florestas indomadas."}
MultiLanguageSpellData['pt'][1250351] = {name = "Depósito Desolado", additional_info = "Alcance de 5m\n2.5 seg de lançamento\n[q]Mineradores que buscam a sorte em K'aresh só encontrarão as escassas ofertas de um mundo devastado. Embora este minério não tenha utilidade para criações algari, os habitantes de Tazavesh podem ver valor no cascalho coletado."}
MultiLanguageSpellData['pt'][1250356] = {name = "Depósito Rico Desolado", additional_info = "Alcance de 5m\n2.5 seg de lançamento\n[q]Mineradores que buscam a sorte em K'aresh só encontrarão as escassas ofertas de um mundo devastado. Embora este minério não tenha utilidade para criações algari, os habitantes de Tazavesh podem ver valor no cascalho coletado.\n\nÀs vezes, depósitos extremamente grandes emergem, para alegria dos mineradores na labuta pelo pão de cada dia."}
